386→// AreHooksInstalled checks if Entire hooks are installed.
387→func (f *FactoryAIDroidAgent) AreHooksInstalled(ctx context.Context) bool {
388→	// Use repo root to find .factory directory when run from a subdirectory
389→	repoRoot, err := paths.WorktreeRoot(ctx)
390→	if err != nil {
391→		repoRoot = "." // Fallback to CWD if not in a git repo
392→	}
393→	settingsPath := filepath.Join(repoRoot, ".factory", FactorySettingsFileName)
394→	data, err := os.ReadFile(settingsPath) //nolint:gosec // path is constructed from repo root + fixed path
395→	if err != nil {
396→		return false
397→	}
398→
399→	var settings FactorySettings
400→	if err := json.Unmarshal(data, &settings); err != nil {
401→		return false
402→	}
403→
404→	// Check for at least one of our hooks (new or old format)
405→	return hookCommandExists(settings.Hooks.Stop, "entire hooks factoryai-droid stop") ||
406→		hookCommandExists(settings.Hooks.Stop, "go run ${FACTORY_PROJECT_DIR}/cmd/entire/main.go hooks factoryai-droid stop")
407→}
