409→// Helper functions for hook management
410→
411→func hookCommandExists(matchers []FactoryHookMatcher, command string) bool {
412→	for _, matcher := range matchers {
413→		for _, hook := range matcher.Hooks {
414→			if hook.Command == command {
415→				return true
416→			}
417→		}
418→	}
419→	return false
420→}
421→
422→func hookCommandExistsWithMatcher(matchers []FactoryHookMatcher, matcherName, command string) bool {
423→	for _, matcher := range matchers {
424→		if matcher.Matcher == matcherName {
425→			for _, hook := range matcher.Hooks {
426→				if hook.Command == command {
427→					return true
428→				}
429→			}
430→		}
431→	}
432→	return false
433→}
434→
435→func addHookToMatcher(matchers []FactoryHookMatcher, matcherName, command string) []FactoryHookMatcher {
436→	entry := FactoryHookEntry{Type: "command", Command: command}
437→	for i := range matchers {
438→		if matchers[i].Matcher == matcherName {
439→			matchers[i].Hooks = append(matchers[i].Hooks, entry)
440→			return matchers
441→		}
442→	}
443→	return append(matchers, FactoryHookMatcher{Matcher: matcherName, Hooks: []FactoryHookEntry{entry}})
444→}
445→
446→// isEntireHook checks if a command is an Entire hook (old or new format)
447→func isEntireHook(command string) bool {
448→	for _, prefix := range entireHookPrefixes {
449→		if strings.HasPrefix(command, prefix) {
450→			return true
451→		}
452→	}
453→	return false
454→}
455→
456→// removeEntireHooks removes all Entire hooks from a list of matchers (for simple hooks like Stop)
457→func removeEntireHooks(matchers []FactoryHookMatcher) []FactoryHookMatcher {
458→	result := make([]FactoryHookMatcher, 0, len(matchers))
459→	for _, matcher := range matchers {
460→		filteredHooks := make([]FactoryHookEntry, 0, len(matcher.Hooks))
461→		for _, hook := range matcher.Hooks {
462→			if !isEntireHook(hook.Command) {
463→				filteredHooks = append(filteredHooks, hook)
464→			}
465→		}
466→		// Only keep the matcher if it has hooks remaining
467→		if len(filteredHooks) > 0 {
468→			matcher.Hooks = filteredHooks
469→			result = append(result, matcher)
470→		}
471→	}
472→	return result
473→}
