231→// waitForTranscriptFlush polls the transcript file for the stop hook sentinel.
232→// Falls back silently after a timeout.
233→func waitForTranscriptFlush(ctx context.Context, transcriptPath string, hookStartTime time.Time) {
234→	const (
235→		maxWait      = 3 * time.Second
236→		pollInterval = 50 * time.Millisecond
237→		tailBytes    = 4096
238→		maxSkew      = 2 * time.Second
239→	)
240→
241→	logCtx := logging.WithComponent(ctx, "agent.claudecode")
242→	deadline := time.Now().Add(maxWait)
243→	for time.Now().Before(deadline) {
244→		if checkStopSentinel(transcriptPath, tailBytes, hookStartTime, maxSkew) {
245→			logging.Debug(logCtx, "transcript flush sentinel found",
246→				slog.Duration("wait", time.Since(hookStartTime)),
247→			)
248→			return
249→		}
250→		time.Sleep(pollInterval)
251→	}
252→	logging.Warn(logCtx, "transcript flush sentinel not found within timeout, proceeding",
253→		slog.Duration("timeout", maxWait),
254→	)
255→}
256→
257→// checkStopSentinel reads the tail of the transcript file and looks for the sentinel.
258→func checkStopSentinel(path string, tailBytes int64, hookStartTime time.Time, maxSkew time.Duration) bool {
259→	f, err := os.Open(path) //nolint:gosec // path comes from agent hook input
260→	if err != nil {
261→		return false
262→	}
263→	defer f.Close()
264→
265→	info, err := f.Stat()
266→	if err != nil {
267→		return false
268→	}
269→	offset := info.Size() - tailBytes
270→	if offset < 0 {
271→		offset = 0
272→	}
273→	buf := make([]byte, info.Size()-offset)
274→	if _, err := f.ReadAt(buf, offset); err != nil {
275→		return false
276→	}
277→
278→	lines := strings.Split(string(buf), "\n")
279→	for _, line := range lines {
280→		line = strings.TrimSpace(line)
281→		if line == "" || !strings.Contains(line, stopHookSentinel) {
282→			continue
283→		}
284→
285→		var entry struct {
286→			Timestamp string `json:"timestamp"`
287→		}
288→		if json.Unmarshal([]byte(line), &entry) != nil || entry.Timestamp == "" {
289→			continue
290→		}
291→		ts, err := time.Parse(time.RFC3339Nano, entry.Timestamp)
292→		if err != nil {
293→			ts, err = time.Parse(time.RFC3339, entry.Timestamp)
294→			if err != nil {
295→				continue
296→			}
297→		}
298→		// Validate timestamp is within acceptable range:
299→		// - Not too far in the past (before hook started minus skew)
300→		// - Not too far in the future (after hook started plus skew)
301→		lowerBound := hookStartTime.Add(-maxSkew)
302→		upperBound := hookStartTime.Add(maxSkew)
303→		if ts.After(lowerBound) && ts.Before(upperBound) {
304→			return true
305→		}
306→	}
307→	return false
308→}
