285→			return 0, nil
286→		}
287→		return 0, fmt.Errorf("failed to open transcript file: %w", err)
288→	}
289→	defer file.Close()
290→
291→	reader := bufio.NewReader(file)
292→	lineCount := 0
293→
294→	for {
295→		line, err := reader.ReadBytes('\n')
296→		if err != nil {
