311→// ExtractModifiedFilesFromOffset extracts files modified since a given line number.
312→// For Claude Code (JSONL format), offset is the starting line number.
313→// Uses bufio.Reader to handle arbitrarily long lines (no size limit).
314→// Returns:
315→//   - files: list of file paths modified by Claude (from Write/Edit tools)
316→//   - currentPosition: total number of lines in the file
317→//   - error: any error encountered during reading
318→func (c *ClaudeCodeAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) (files []string, currentPosition int, err error) {
319→	if path == "" {
320→		return nil, 0, nil
321→	}
322→
323→	file, openErr := os.Open(path) //nolint:gosec // Path comes from Claude Code transcript location
324→	if openErr != nil {
325→		return nil, 0, fmt.Errorf("failed to open transcript file: %w", openErr)
326→	}
327→	defer file.Close()
328→
329→	reader := bufio.NewReader(file)
330→	var lines []TranscriptLine
331→	lineNum := 0
332→
333→	for {
334→		lineData, readErr := reader.ReadBytes('\n')
335→		if readErr != nil && readErr != io.EOF {
336→			return nil, 0, fmt.Errorf("failed to read transcript: %w", readErr)
337→		}
338→
339→		if len(lineData) > 0 {
340→			lineNum++
341→			if lineNum > startOffset {
342→				var line TranscriptLine
343→				if parseErr := json.Unmarshal(lineData, &line); parseErr == nil {
344→					lines = append(lines, line)
345→				}
346→				// Skip malformed lines silently
347→			}
348→		}
349→
350→		if readErr == io.EOF {
351→			break
352→		}
353→	}
354→
355→	return ExtractModifiedFiles(lines), lineNum, nil
356→}
